impl crate::core::types::HoudiniNode for SopPolybevel {
    fn get_id(&self) -> usize {
        self.id
    }

    fn get_name(&self) -> &str {
        &self.name
    }

    fn get_node_type(&self) -> &'static str {
        "polybevel"
    }

    fn get_inputs(&self) -> &std::collections::BTreeMap<usize, (usize, usize)> {
        &self.inputs
    }

    fn get_params(&self) -> &std::collections::HashMap<String, crate::core::types::ParamValue> {
        &self.params
    }

    fn get_spare_params(&self) -> &[crate::core::types::SpareParam] {
        &self.spare_params
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum SopPolybridgeSpinetype {
    Straight = 0,
    Curved = 1,
    CurveFromSecondInput = 2,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum SopPolybridgeSrcsplittype {
    IndividualElements = 0,
    ConnectedComponents = 1,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum SopPolybridgeSrcdirsign {
    AutoUsing = 0,
    Along = 1,
    Opposite = 2,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum SopPolybridgeUsesrcdir {
    LoopNormal = 0,
    ExplicitDirection = 1,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum SopPolybridgeDstsplittype {
    IndividualElements = 0,
    ConnectedComponents = 1,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
