pub enum SopPolybridgeUsedstdir {
    LoopNormal = 0,
    ExplicitDirection = 1,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum SopPolybridgeSpacing {
    Uniform = 0,
    CurvatureSensitive = 1,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum SopPolybridgeSpinepos {
    AsIs = 0,
    /// Start at Source, End at Destination
    StartAtSourceEndAtDestination = 1,
    /// Start at Source, End Along Source Direction
    StartAtSourceEndAlongSourceDirection = 2,
    /// End at Destination, Start Along Destination Direction
    EndAtDestinationStartAlongDestinationDirection = 3,
    /// Start at Source, Tangent to Source Direction
    StartAtSourceTangentToSourceDirection = 4,
    /// End at Destination, Tangent to Destination Direction
    EndAtDestinationTangentToDestinationDirection = 5,
    TranslateStartToSource = 6,
    TranslateEndToDestination = 7,
}

